        let logMessage = """
        API Call - Endpoint: \(endpoint)
        Request Payload: \(requestPayload)
        Response Payload: \(responsePayload ?? "N/A")
        Error: \(error?.localizedDescription ?? "N/A")
        """
        NSLog(logMessage)
    }

    func logUserDataChange(userId: String?, changedData: [String: Any]) {
        let logMessage = "User Data Change - User ID: \(userId ?? "N/A"), Changed Data: \(changedData)"
        NSLog(logMessage)
    }

    func logErrorCondition(error: Error, userId: String?) {
        let logMessage = "Error Condition - User ID: \(userId ?? "N/A"), Error: \(error.localizedDescription)"
